import { useState } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import {
  Box, Typography, Button, Paper, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, IconButton, Tooltip, Dialog, DialogTitle, DialogContent,
  DialogActions, TextField, CircularProgress,
} from '@mui/material'
import AddIcon from '@mui/icons-material/Add'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'

// Generated by: npm run generate-api
import {
  useListCompanies,
  useCreateCompany,
  useDeleteCompany,
  getListCompaniesQueryKey,
} from '../../api/companies/companies'

export default function CompaniesPage() {
  const queryClient = useQueryClient()
  const [open, setOpen] = useState(false)
  const [name, setName] = useState('')

  const { data: companiesPage, isLoading } = useListCompanies()
  const companies = companiesPage?.items ?? []

  const { mutate: createCompany, isPending: creating } = useCreateCompany({
    mutation: {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListCompaniesQueryKey() })
        setOpen(false)
        setName('')
      },
    },
  })

  const { mutate: deleteCompany } = useDeleteCompany({
    mutation: {
      onSuccess: () => queryClient.invalidateQueries({ queryKey: getListCompaniesQueryKey() }),
    },
  })

  return (
    <Box sx={{ p: 3, height: '100%', overflow: 'auto' }}>
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
        <Typography variant="h6" fontWeight={600} sx={{ flex: 1 }}>
          Companies
        </Typography>
        <Button variant="contained" startIcon={<AddIcon />} onClick={() => setOpen(true)}>
          New Company
        </Button>
      </Box>

      {isLoading ? (
        <CircularProgress />
      ) : (
        <TableContainer component={Paper} elevation={1}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell sx={{ fontWeight: 600 }}>Name</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>ID</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Created</TableCell>
                <TableCell width={60} />
              </TableRow>
            </TableHead>
            <TableBody>
              {companies.length === 0 && (
                <TableRow>
                  <TableCell colSpan={4}>
                    <Typography variant="body2" color="text.secondary" textAlign="center" py={2}>
                      No companies yet.
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
              {companies.map((c) => (
                <TableRow key={c.id as string} hover>
                  <TableCell>{c.name}</TableCell>
                  <TableCell>
                    <Tooltip title="Click to copy">
                      <Typography
                        variant="caption"
                        fontFamily="monospace"
                        sx={{ cursor: 'pointer', color: 'text.secondary' }}
                        onClick={() => navigator.clipboard.writeText(c.id as string)}
                      >
                        {c.id as string}
                      </Typography>
                    </Tooltip>
                  </TableCell>
                  <TableCell>{new Date(c.created_at).toLocaleDateString()}</TableCell>
                  <TableCell>
                    <Tooltip title="Delete">
                      <IconButton
                        size="small"
                        color="error"
                        onClick={() => {
                          if (confirm(`Delete "${c.name}" and all its labs and users?`))
                            deleteCompany({ companyId: c.id as string })
                        }}
                      >
                        <DeleteOutlineIcon fontSize="small" />
                      </IconButton>
                    </Tooltip>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>New Company</DialogTitle>
        <DialogContent>
          <TextField
            autoFocus
            label="Company name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && createCompany({ data: { name } })}
            fullWidth
            size="small"
            sx={{ mt: 1 }}
          />
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>Cancel</Button>
          <Button
            variant="contained"
            disabled={!name.trim() || creating}
            onClick={() => createCompany({ data: { name } })}
          >
            Create
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  )
}
